/**
 * DisplayTab Component
 * Display and appearance settings
 */

import React, { useState } from 'react';
import { UserSettings, DisplaySettings, Theme, FontSize, Density, Language, DateFormat, TimeFormat, getThemeLabel, getFontSizeLabel, getDensityLabel, getLanguageLabel } from '../../../models/Settings';
import styles from './DisplayTab.module.css';

interface DisplayTabProps {
  settings: UserSettings;
  onSave: (settings: Partial<UserSettings>) => void;
  saving: boolean;
}

export const DisplayTab: React.FC<DisplayTabProps> = ({ settings, onSave, saving }) => {
  const [display, setDisplay] = useState<DisplaySettings>(settings.display);

  const handleChange = (field: keyof DisplaySettings, value: any) => {
    const newDisplay = {
      ...display,
      [field]: value,
    };
    setDisplay(newDisplay);
    
    // Auto-apply theme changes
    if (field === 'theme') {
      onSave({ display: newDisplay });
    }
  };

  const handleSave = () => {
    onSave({ display });
  };

  return (
    <div className={styles.displayTab}>
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <h3 className={styles.cardTitle}>Cài đặt Hiển thị</h3>
          <p className={styles.cardDescription}>
            Tùy chỉnh giao diện và hiển thị của hệ thống
          </p>
        </div>

        <div className={styles.cardBody}>
          {/* Theme */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Giao diện</label>
            <div className={styles.themeOptions}>
              {Object.values(Theme).map((theme) => (
                <div
                  key={theme}
                  className={`${styles.themeCard} ${display.theme === theme ? styles.active : ''}`}
                  onClick={() => handleChange('theme', theme)}
                >
                  <div className={`${styles.themePreview} ${styles[`theme${theme}`]}`}>
                    <div className={styles.previewHeader}></div>
                    <div className={styles.previewBody}>
                      <div className={styles.previewSidebar}></div>
                      <div className={styles.previewContent}></div>
                    </div>
                  </div>
                  <div className={styles.themeName}>{getThemeLabel(theme)}</div>
                  {display.theme === theme && (
                    <div className={styles.activeIndicator}>
                      <i className="fas fa-check-circle"></i>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Font Size */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Kích thước chữ</label>
            <select
              className={styles.select}
              value={display.fontSize}
              onChange={(e) => handleChange('fontSize', e.target.value as FontSize)}
            >
              {Object.values(FontSize).map((size) => (
                <option key={size} value={size}>
                  {getFontSizeLabel(size)}
                </option>
              ))}
            </select>
          </div>

          {/* Density */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Mật độ hiển thị</label>
            <select
              className={styles.select}
              value={display.density}
              onChange={(e) => handleChange('density', e.target.value as Density)}
            >
              {Object.values(Density).map((density) => (
                <option key={density} value={density}>
                  {getDensityLabel(density)}
                </option>
              ))}
            </select>
          </div>

          {/* Language */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Ngôn ngữ</label>
            <select
              className={styles.select}
              value={display.language}
              onChange={(e) => handleChange('language', e.target.value as Language)}
            >
              {Object.values(Language).map((lang) => (
                <option key={lang} value={lang}>
                  {getLanguageLabel(lang)}
                </option>
              ))}
            </select>
          </div>

          {/* Date Format */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Định dạng ngày</label>
            <select
              className={styles.select}
              value={display.dateFormat}
              onChange={(e) => handleChange('dateFormat', e.target.value as DateFormat)}
            >
              {Object.values(DateFormat).map((format) => (
                <option key={format} value={format}>
                  {format}
                </option>
              ))}
            </select>
          </div>

          {/* Time Format */}
          <div className={styles.formGroup}>
            <label className={styles.label}>Định dạng giờ</label>
            <select
              className={styles.select}
              value={display.timeFormat}
              onChange={(e) => handleChange('timeFormat', e.target.value as TimeFormat)}
            >
              {Object.values(TimeFormat).map((format) => (
                <option key={format} value={format}>
                  {format === TimeFormat.Format24 ? '24 giờ' : '12 giờ'}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div className={styles.cardFooter}>
          <button
            onClick={handleSave}
            className={styles.saveButton}
            disabled={saving}
          >
            {saving ? (
              <>
                <i className="fas fa-spinner fa-spin"></i> Đang lưu...
              </>
            ) : (
              <>
                <i className="fas fa-save"></i> Lưu thay đổi
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};
