import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAppSelector } from '../../store/hooks';
import { getHomePath } from '@linm-soft/common-components';
import './UnauthorizedPage.css';

const UnauthorizedPage: React.FC = () => {
  const navigate = useNavigate();
  const user = useAppSelector((state) => state.auth.user);
  const homePath = getHomePath(user?.role, user?.package);

  return (
    <div className="unauthorized-page">
      <div className="unauthorized-container">
        <div className="unauthorized-icon">🚫</div>
        <h1 className="unauthorized-code">403</h1>
        <h2 className="unauthorized-title">Không có quyền truy cập</h2>
        <p className="unauthorized-description">
          Bạn không có quyền truy cập vào trang này.
          <br />
          Vui lòng liên hệ quản trị viên nếu bạn cần trợ giúp.
        </p>
        <div className="unauthorized-actions">
          <button className="btn-primary" onClick={() => navigate(homePath, { replace: true })}>
            🏠 Về trang chủ
          </button>
          <button className="btn-secondary" onClick={() => navigate(-1)}>
            ← Quay lại
          </button>
        </div>
      </div>
    </div>
  );
};

export default UnauthorizedPage;
