/**
 * SecurityTab Component
 * Security settings and password change
 */

import React, { useState } from 'react';
import { UserSettings } from '../../../models/Settings';
import { ChangePasswordModal } from '../../auth/ForceChangePasswordSlideout';
import styles from './SecurityTab.module.css';

interface SecurityTabProps {
  settings: UserSettings;
  onSave: (settings: Partial<UserSettings>) => void;
  saving: boolean;
}

export const SecurityTab: React.FC<SecurityTabProps> = ({ settings, onSave, saving }) => {
  const [security, setSecurity] = useState(settings.security);
  const [showPasswordModal, setShowPasswordModal] = useState(false);

  const handleSecurityChange = (field: string, value: any) => {
    setSecurity((prev) => ({
      ...prev,
      [field]: value,
    }));
  };

  const handleSave = () => {
    onSave({ security });
  };

  const daysSincePasswordChange = settings.security.lastPasswordChange
    ? Math.floor(
        (Date.now() - new Date(settings.security.lastPasswordChange).getTime()) / (1000 * 60 * 60 * 24)
      )
    : null;

  return (
    <div className={styles.securityTab}>
      {/* Change Password */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <h3 className={styles.cardTitle}>Đổi mật khẩu</h3>
          <p className={styles.cardDescription}>
            Đảm bảo tài khoản của bạn sử dụng mật khẩu mạnh và an toàn
          </p>
        </div>

        <div className={styles.cardBody}>
          {daysSincePasswordChange !== null && (
            <div className={styles.lastChange}>
              <i className="fas fa-info-circle"></i>
              Lần đổi mật khẩu gần nhất: {daysSincePasswordChange} ngày trước
            </div>
          )}

          <div className={styles.passwordRequirements}>
            <div className={styles.requirementTitle}>Yêu cầu mật khẩu:</div>
            <ul className={styles.requirementList}>
              <li>Ít nhất 8 ký tự</li>
              <li>Có ít nhất 1 chữ hoa</li>
              <li>Có ít nhất 1 chữ thường</li>
              <li>Có ít nhất 1 số</li>
              <li>Có ít nhất 1 ký tự đặc biệt</li>
            </ul>
          </div>

          <button
            type="button"
            className={styles.changePasswordButton}
            onClick={() => setShowPasswordModal(true)}
          >
            <i className="fas fa-key"></i> Đổi mật khẩu
          </button>
        </div>
      </div>

      {/* Security Settings */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <h3 className={styles.cardTitle}>Cài đặt Bảo mật</h3>
          <p className={styles.cardDescription}>
            Quản lý các tùy chọn bảo mật cho tài khoản của bạn
          </p>
        </div>

        <div className={styles.cardBody}>
          <div className={styles.formGroup}>
            <label className={styles.checkboxLabel}>
              <input
                type="checkbox"
                checked={security.twoFactorEnabled}
                onChange={(e) => handleSecurityChange('twoFactorEnabled', e.target.checked)}
              />
              <div>
                <span className={styles.checkboxTitle}>Xác thực hai yếu tố (2FA)</span>
                <span className={styles.checkboxDescription}>
                  Thêm lớp bảo mật bổ sung bằng mã xác thực qua ứng dụng
                </span>
              </div>
            </label>
          </div>

          <div className={styles.formGroup}>
            <label className={styles.label}>Thời gian chờ phiên làm việc (phút)</label>
            <select
              className={styles.select}
              value={security.sessionTimeout}
              onChange={(e) => handleSecurityChange('sessionTimeout', parseInt(e.target.value))}
            >
              <option value="15">15 phút</option>
              <option value="30">30 phút</option>
              <option value="60">60 phút</option>
              <option value="120">120 phút</option>
            </select>
            <span className={styles.helpText}>
              Tự động đăng xuất sau khoảng thời gian không hoạt động
            </span>
          </div>
        </div>

        <div className={styles.cardFooter}>
          <button
            onClick={handleSave}
            className={styles.saveButton}
            disabled={saving}
          >
            {saving ? (
              <>
                <i className="fas fa-spinner fa-spin"></i> Đang lưu...
              </>
            ) : (
              <>
                <i className="fas fa-save"></i> Lưu thay đổi
              </>
            )}
          </button>
        </div>
      </div>

      {/* Change Password Modal */}
      <ChangePasswordModal
        isOpen={showPasswordModal}
        isForced={false}
        onClose={() => setShowPasswordModal(false)}
      />
    </div>
  );
};
