import React, { useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { useConversations } from '../../hooks/useConversations';
import { ConversationList } from './components/ConversationList/ConversationList';
import { ChatPanel } from './components/ChatPanel/ChatPanel';
import { conversationEndpoint } from '../../services/message/conversationEndpoint';
import { useAppDispatch } from '../../store/hooks';
import { clearUnreadMessages, markConversationReadLocal } from '../../store/slices/messagesInboxSlice';
import styles from './MessagesPage.module.css';

/**
 * MessagesPage — Inbox-style page that shows all conversations (type='message')
 * across tickets and tasks where the current user is a participant.
 *
 * URL support:
 *   /messages                     → list only (or auto-selects first conversation on desktop)
 *   /messages/:entityType/:entityId → deep-link opens that conversation
 */
const MessagesPage: React.FC = () => {
  useNavTitle('Tin nhắn');
  const { entityType, entityId } = useParams<{ entityType?: string; entityId?: string }>();
  const navigate = useNavigate();
  const dispatch = useAppDispatch();

  const {
    conversations,
    loading,
    hasMore,
    selectedEntityId,
    selectedEntityType,
    selectedConversation,
    reload,
    loadMore,
    selectConv,
    clearSelection,
  } = useConversations();

  // Deep-link: auto-select from URL params on first render
  useEffect(() => {
    if (entityId && entityType &&
        (entityType === 'ticket' || entityType === 'task' || entityType === 'incident')) {
      selectConv(entityId, entityType as 'ticket' | 'task' | 'incident');
    }
  }, [entityId, entityType, selectConv]);

  // Clear top badge when user lands on /messages
  useEffect(() => {
    dispatch(clearUnreadMessages());
  }, [dispatch]);

  // When a conversation is selected, update URL + mark as read
  const handleSelect = (id: string, type: 'ticket' | 'task' | 'incident') => {
    selectConv(id, type);
    navigate(`/messages/${type}/${id}`, { replace: true });
    dispatch(markConversationReadLocal(id));
    conversationEndpoint.markConversationRead(type, id).catch(() => {});
  };

  const handleBack = () => {
    clearSelection();
    navigate('/messages', { replace: true });
  };

  // Mobile: show list OR chat (not both); desktop: show both
  const showList = !selectedEntityId;
  const showChat = !!selectedEntityId;

  return (
    <div className={styles.page}>
      {/* ── LEFT: Conversation list ─────────────────────────── */}
      <aside className={`${styles.sidebar} ${showChat ? styles.hiddenMobile : ''}`}>
        <div className={styles.sidebarHeader}>
          <h2 className={styles.sidebarTitle}>
            <i className="fas fa-comments" /> Tin nhắn
          </h2>
          <button className={styles.reloadBtn} onClick={reload} title="Tải lại">
            <i className="fas fa-sync-alt" />
          </button>
        </div>

        <ConversationList
          conversations={conversations}
          selectedEntityId={selectedEntityId}
          selectedEntityType={selectedEntityType}
          loading={loading}
          hasMore={hasMore}
          onSelect={handleSelect}
          onLoadMore={loadMore}
          onReload={reload}
        />
      </aside>

      {/* ── RIGHT: Chat panel ───────────────────────────────── */}
      <main className={`${styles.chatArea} ${showList ? styles.hiddenMobile : ''}`}>
        {selectedConversation ? (
          <>
            {/* Mobile back button */}
            <button className={styles.backBtn} onClick={handleBack}>
              <i className="fas fa-arrow-left" /> Danh sách
            </button>
            <ChatPanel conversation={selectedConversation} />
          </>
        ) : (
          <div className={styles.emptyState}>
            <i className="fas fa-comments" />
            <p>Chọn một cuộc hội thoại để bắt đầu</p>
          </div>
        )}
      </main>
    </div>
  );
};

export default MessagesPage;
