import { User, UserRole } from '../../models/User';
import type { UUID } from '../../models/common';
import type { AuthUserInfo, AuthLoginResponse, LoginResponse } from './responseModel';

/** Role strings returned by AuthenticationService → frontend UserRole enum */
const ROLE_MAP: Record<string, UserRole> = {
  Admin:   UserRole.Admin,
  admin:   UserRole.Admin,
  Manager: UserRole.Manager,
  manager: UserRole.Manager,
  Staff:   UserRole.Staff,
  staff:   UserRole.Staff,
};

/**
 * Map AuthenticationService UserInfoDto → frontend User model.
 *
 * Differences handled:
 * - `phoneNumber` → `username`
 * - `roles: string[]` → single `role: UserRole` (highest privilege wins)
 * - Vietnamese name split: last word = firstName, rest = lastName
 */
export const mapAuthUser = (authUser: AuthUserInfo): User => {
  const parts     = authUser.fullName.trim().split(/\s+/);
  const firstName = parts[parts.length - 1] ?? '';
  const lastName  = parts.slice(0, -1).join(' ');

  const role =
    authUser.roles.reduce<UserRole | undefined>(
      (found, r) => found ?? ROLE_MAP[r],
      undefined
    ) ?? UserRole.Staff;
  console.log('[auth mapper] raw roles=', authUser.roles, '→ mapped role=', role);

  return {
    id:             authUser.id as UUID,
    username:       authUser.phoneNumber,
    email:          authUser.email ?? '',
    firstName,
    lastName,
    fullName:       authUser.fullName,
    role,
    departmentId:   (authUser.departmentId ?? '') as UUID,
    departmentName: '',
    skills:         [],
    avatar:         undefined,
    isActive:       authUser.isActive,
    createdAt:      authUser.createdAt,
    updatedAt:      new Date().toISOString(),
    requirePasswordChange: authUser.requirePasswordChange ?? false,
    employeeId:     authUser.employeeId,
    package:        authUser.package ?? 'Basic',
    defaultMenuUrl: authUser.defaultMenuUrl,
    companyId:      authUser.companyId,
  };
};

/**
 * Map raw AuthenticationService login response → frontend LoginResponse shape.
 */
export const mapLoginResponse = (raw: AuthLoginResponse): LoginResponse => ({
  token: raw.token,
  refreshToken: raw.refreshToken,
  user:  mapAuthUser(raw.user),
});
