import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAppSelector } from '../../store/hooks';
import { UserRole } from '../../models/User';
import { getHomePath, isPathAllowed } from '@linm-soft/common-components';

interface ProtectedRouteProps {
  children: React.ReactNode;
  allowedRoles?: UserRole[];
}

/**
 * Protected route component that requires authentication.
 *
 * Guard order:
 *  1. Not authenticated → redirect to /login
 *  2. allowedRoles specified but user's role not included → redirect to /unauthorized
 *  3. Current path not covered by the user's menu → redirect to /unauthorized
 */
export const ProtectedRoute: React.FC<ProtectedRouteProps> = ({
  children,
  allowedRoles,
}) => {
  const { isAuthenticated, user } = useAppSelector((state) => state.auth);
  const location = useLocation();


  // 1. Not authenticated — redirect to login.
  //    Also treat stale isAuthenticated=true without a token as unauthenticated
  //    (can happen when another MFE clears localStorage without a hard reload).
  if (!isAuthenticated || !localStorage.getItem('auth_token')) {
    return <Navigate to="/login" replace />;
  }
  if (location.pathname === '/') {
    var homePatch = getHomePath(user?.role, user?.package, user?.defaultMenuUrl);
    return <Navigate to={homePatch} replace />;
  }
  // 2. Explicit role restriction (legacy support)
  if (allowedRoles && allowedRoles.length > 0 && user) {
    if (!allowedRoles.includes(user.role)) {
      return <Navigate to="/unauthorized" replace />;
    }
  }

  // 3. Menu-based path guard
  //    Check whether the current pathname is accessible via the user's menu.
  //    Uses prefix matching so detail pages (/tickets/123) inherit their
  //    parent list page (/tickets) access.
  if (user && !isPathAllowed(user.role, user.package, location.pathname)) {
    return <Navigate to="/unauthorized" replace />;
  }

  // Authenticated and authorised — render children
  return <>{children}</>;
};
