const BRANDING_KEY = 'company_branding';

export interface CompanyBranding {
  id: string;
  code: string;
  name: string;
  shortName?: string;
  logoUrl?: string;
}

export const companyBrandingService = {
  get(): CompanyBranding | null {
    try {
      const raw = localStorage.getItem(BRANDING_KEY);
      return raw ? (JSON.parse(raw) as CompanyBranding) : null;
    } catch {
      return null;
    }
  },

  set(b: CompanyBranding): void {
    localStorage.setItem(BRANDING_KEY, JSON.stringify(b));
  },

  clear(): void {
    localStorage.removeItem(BRANDING_KEY);
  },

  /** Returns the company logo URL, or falls back to the default app icon. */
  getInstallLogo(baseUrl = '/'): string {
    return this.get()?.logoUrl ?? `${baseUrl}icons/logo.png`;
  },

  /** Fetch by company code from public API, store and return. */
  async fetchByCode(code: string, apiUrl: string): Promise<CompanyBranding | null> {
    try {
      const res = await fetch(`${apiUrl}/companies/by-code/${encodeURIComponent(code)}`);
      if (!res.ok) return null;
      const json = (await res.json()) as { data?: Record<string, unknown> } & Record<string, unknown>;
      const data = (json.data ?? json) as {
        id: string;
        name: string;
        shortName?: string;
        logoUrl?: string;
      };
      const branding: CompanyBranding = {
        id: data.id,
        code,
        name: data.name,
        shortName: data.shortName,
        logoUrl: data.logoUrl,
      };
      this.set(branding);
      return branding;
    } catch {
      return null;
    }
  },

  /** Fetch by company ID (after login), update stored branding. */
  async fetchById(id: string, apiUrl: string): Promise<void> {
    try {
      const res = await fetch(`${apiUrl}/companies/public/${id}`);
      if (!res.ok) return;
      const json = (await res.json()) as { data?: Record<string, unknown> } & Record<string, unknown>;
      const data = (json.data ?? json) as {
        id: string;
        name: string;
        shortName?: string;
        logoUrl?: string;
      };
      const current = this.get();
      this.set({
        id: data.id,
        code: current?.code ?? '',
        name: data.name,
        shortName: data.shortName,
        logoUrl: data.logoUrl,
      });
    } catch {
      /* ignore */
    }
  },
};
