/**
 * SettingsPage Component
 * Main container for user settings with tabbed interface
 */

import React, { useState, useEffect } from 'react';
import { useNavTitle } from '@linm-soft/common-components';
import { settingsService } from '../../services/settingsService';
import { authService } from '../../services/authService';
import { UserSettings, SystemSettings } from '../../models/Settings';
import { useAppToast } from '../../hooks/useAppToast';
import { ProfileTab } from '../../components/settings/ProfileTab';
import { NotificationsTab } from '../../components/settings/NotificationsTab';
import { DisplayTab } from '../../components/settings/DisplayTab';
import { SecurityTab } from '../../components/settings/SecurityTab';
import { PrivacyTab } from '../../components/settings/PrivacyTab';
import { SystemTab } from '../../components/settings/SystemTab';
import { AboutTab } from '../../components/settings/AboutTab';
import styles from './SettingsPage.module.css';

type SettingsTab = 'profile' | 'notifications' | 'display' | 'security' | 'privacy' | 'system' | 'about';

const SettingsPage: React.FC = () => {
  useNavTitle('Cài đặt');
  const toast = useAppToast();
  const [activeTab, setActiveTab] = useState<SettingsTab>('profile');
  const [settings, setSettings] = useState<UserSettings | null>(null);
  const [systemSettings, setSystemSettings] = useState<SystemSettings | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'success' | 'error'>('idle');
  const [retryKey, setRetryKey] = useState(0);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    const timer = setTimeout(() => {
      if (cancelled) return;
      Promise.all([
        settingsService.getUserSettings(),
        settingsService.getSystemSettings(),
        authService.getCurrentUser().catch(() => null), // non-fatal if offline
      ])
        .then(([userData, systemData, authUser]) => {
          if (cancelled) return;
          // Merge: supplement BFF data with fresh Auth-service data where applicable
          const merged: UserSettings = authUser
            ? {
                ...userData,
                profile: {
                  ...userData.profile,
                  // Phone: prefer whatever the user last saved in BFF;
                  // fall back to the number from the Auth service (username field)
                  phone: userData.profile.phone || authUser.username || undefined,
                  // Email: strip auto-generated @hospital.vn placeholder addresses
                  email: userData.profile.email?.endsWith('@hospital.vn')
                    ? undefined
                    : userData.profile.email,
                },
              }
            : userData;
          setSettings(merged);
          setSystemSettings(systemData);
        })
        .catch((err: unknown) => {
          if (cancelled) return;
          toast.fromError(err, 'Không thể tải cài đặt');
          setError('Không thể tải cài đặt');
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [retryKey]); // eslint-disable-line react-hooks/exhaustive-deps

  const handleSave = async (updatedSettings: Partial<UserSettings>) => {
    try {
      setSaveStatus('saving');
      const updated = await settingsService.updateUserSettings(updatedSettings);
      setSettings(updated);
      setSaveStatus('success');
      
      // Reset success message after 3 seconds
      setTimeout(() => {
        setSaveStatus('idle');
      }, 3000);
    } catch (err: unknown) {
      toast.fromError(err, 'Đã có lỗi khi lưu cài đặt');
      setSaveStatus('error');
      setTimeout(() => {
        setSaveStatus('idle');
      }, 3000);
    }
  };

  const tabs: { id: SettingsTab; label: string; icon: string }[] = [
    { id: 'profile', label: 'Hồ sơ', icon: 'fas fa-user' },
    { id: 'notifications', label: 'Thông báo', icon: 'fas fa-bell' },
    { id: 'display', label: 'Hiển thị', icon: 'fas fa-palette' },
    { id: 'security', label: 'Bảo mật', icon: 'fas fa-shield-alt' },
    { id: 'privacy', label: 'Riêng tư', icon: 'fas fa-lock' },
    { id: 'system', label: 'Hệ thống', icon: 'fas fa-building' },
    { id: 'about', label: 'Về ứng dụng', icon: 'fas fa-info-circle' },
  ];

  if (loading && !settings) {
    return (
      <div className={styles.loading}>
        <i className="fas fa-spinner fa-spin"></i>
        <p>Đang tải cài đặt...</p>
      </div>
    );
  }

  if (error && !settings) {
    return (
      <div className={styles.error}>
        <i className="fas fa-exclamation-circle"></i>
        <p>{error}</p>
        <button onClick={() => setRetryKey((k) => k + 1)} className={styles.retryButton}>
          <i className="fas fa-redo"></i> Thử lại
        </button>
      </div>
    );
  }

  if (!settings) {
    return null;
  }

  return (
    <div className={styles.settingsPage}>
      {/* Page Header */}
      <div className={styles.pageHeader}>
        <div>
          <h1 className={styles.pageTitle}>
            <i className="fas fa-cog"></i>
            Cài đặt
          </h1>
          <p className={styles.pageDescription}>
            Quản lý tùy chỉnh và cài đặt cá nhân của bạn
          </p>
        </div>
      </div>

      {/* Save Status Notification */}
      {saveStatus === 'success' && (
        <div className={styles.successNotification}>
          <i className="fas fa-check-circle"></i>
          <span>Đã lưu thay đổi thành công</span>
        </div>
      )}

      {saveStatus === 'error' && (
        <div className={styles.errorNotification}>
          <i className="fas fa-exclamation-circle"></i>
          <span>Không thể lưu thay đổi. Vui lòng thử lại.</span>
        </div>
      )}

      {/* Settings Content */}
      <div className={styles.settingsContent}>
        {/* Sidebar Navigation */}
        <div className={styles.settingsNav}>
          <div className={styles.navCard}>
            {tabs.map((tab) => (
              <button
                key={tab.id}
                className={`${styles.navItem} ${activeTab === tab.id ? styles.active : ''}`}
                onClick={() => setActiveTab(tab.id)}
              >
                <i className={tab.icon}></i>
                <span>{tab.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Tab Content */}
        <div className={styles.settingsPanel}>
          {activeTab === 'profile' && (
            <ProfileTab
              settings={settings}
              onSave={handleSave}
              saving={saveStatus === 'saving'}
            />
          )}

          {activeTab === 'notifications' && (
            <NotificationsTab
              settings={settings}
              onSave={handleSave}
              saving={saveStatus === 'saving'}
            />
          )}

          {activeTab === 'display' && (
            <DisplayTab
              settings={settings}
              onSave={handleSave}
              saving={saveStatus === 'saving'}
            />
          )}

          {activeTab === 'security' && (
            <SecurityTab
              settings={settings}
              onSave={handleSave}
              saving={saveStatus === 'saving'}
            />
          )}

          {activeTab === 'privacy' && (
            <PrivacyTab
              settings={settings}
              onSave={handleSave}
              saving={saveStatus === 'saving'}
            />
          )}

          {activeTab === 'system' && systemSettings && (
            <SystemTab systemSettings={systemSettings} />
          )}

          {activeTab === 'about' && (
            <AboutTab />
          )}
        </div>
      </div>
    </div>
  );
};

export default SettingsPage;
