import React from 'react';
import { Provider } from 'react-redux';
import { store } from './store/store';
import App from './App';
import singleSpaReact from 'single-spa-react';
import { createRoot } from 'react-dom/client';
import './styles/global.css';

// Mobile viewport height fix — same as source index.tsx.
// CSS 100dvh is not supported in all mobile browsers; fall back to
// setting --app-height via JS so the login screen fills exactly the
// visible viewport (no gap under the iOS address bar).
const setAppHeight = () => {
  document.documentElement.style.setProperty('--app-height', `${window.innerHeight}px`);
};
if (!CSS.supports('height', '100dvh')) {
  setAppHeight();
  window.addEventListener('resize', setAppHeight);
  window.addEventListener('orientationchange', setAppHeight);
}

const Root: React.FC = () => (
  <Provider store={store}>
    <App />
  </Provider>
);

const lifecycles = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: Root as any,
  errorBoundary(_error: Error, _info: React.ErrorInfo, _props: unknown) {
    return (
      <div style={{ padding: '2rem', color: '#c62828' }}>
        <h2>Lỗi ứng dụng</h2>
        <button onClick={() => window.location.reload()}>Tải lại</button>
      </div>
    );
  },
  renderType: 'createRoot',
});

export const { bootstrap, mount, unmount } = lifecycles;
