import React, { useState } from 'react';
import {
  SupportTicketCreate,
  HelpCategory,
  SupportPriority,
} from '../../../models/Help';
import { getAllCategories } from '../../../models/Help';
import styles from './ContactForm.module.css';

interface ContactFormProps {
  onSubmit: (ticket: SupportTicketCreate) => void;
  submitting: boolean;
}

export const ContactForm: React.FC<ContactFormProps> = ({
  onSubmit,
  submitting,
}) => {
  const categories = getAllCategories();
  
  const [formData, setFormData] = useState<SupportTicketCreate>({
    subject: '',
    description: '',
    category: 'general' as HelpCategory,
    priority: 'medium' as SupportPriority,
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const handleChange = (
    field: keyof SupportTicketCreate,
    value: string | HelpCategory | SupportPriority
  ) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    // Clear error when user types
    if (errors[field]) {
      setErrors((prev) => {
        const newErrors = { ...prev };
        delete newErrors[field];
        return newErrors;
      });
    }
  };

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!formData.subject.trim()) {
      newErrors.subject = 'Vui lòng nhập tiêu đề';
    }

    if (!formData.description.trim()) {
      newErrors.description = 'Vui lòng nhập mô tả chi tiết';
    } else if (formData.description.trim().length < 20) {
      newErrors.description = 'Mô tả phải có ít nhất 20 ký tự';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    
    if (validate()) {
      onSubmit(formData);
    }
  };

  return (
    <form className={styles.form} onSubmit={handleSubmit}>
      {/* Subject */}
      <div className={styles.field}>
        <label className={styles.label} htmlFor="subject">
          Tiêu đề <span className={styles.required}>*</span>
        </label>
        <input
          id="subject"
          type="text"
          className={`${styles.input} ${errors.subject ? styles.error : ''}`}
          value={formData.subject}
          onChange={(e) => handleChange('subject', e.target.value)}
          placeholder="Nhập tiêu đề ngắn gọn"
          disabled={submitting}
        />
        {errors.subject && (
          <span className={styles.errorText}>{errors.subject}</span>
        )}
      </div>

      {/* Category */}
      <div className={styles.field}>
        <label className={styles.label} htmlFor="category">
          Danh mục <span className={styles.required}>*</span>
        </label>
        <select
          id="category"
          className={styles.select}
          value={formData.category}
          onChange={(e) => handleChange('category', e.target.value as HelpCategory)}
          disabled={submitting}
        >
          {categories.map((cat) => (
            <option key={cat.id} value={cat.id}>
              {cat.icon} {cat.label}
            </option>
          ))}
        </select>
      </div>

      {/* Priority */}
      <div className={styles.field}>
        <label className={styles.label} htmlFor="priority">
          Mức độ ưu tiên <span className={styles.required}>*</span>
        </label>
        <select
          id="priority"
          className={styles.select}
          value={formData.priority}
          onChange={(e) => handleChange('priority', e.target.value as SupportPriority)}
          disabled={submitting}
        >
          <option value="low">Thấp</option>
          <option value="medium">Trung bình</option>
          <option value="high">Cao</option>
          <option value="urgent">Khẩn cấp</option>
        </select>
      </div>

      {/* Description */}
      <div className={styles.field}>
        <label className={styles.label} htmlFor="description">
          Mô tả chi tiết <span className={styles.required}>*</span>
        </label>
        <textarea
          id="description"
          className={`${styles.textarea} ${errors.description ? styles.error : ''}`}
          value={formData.description}
          onChange={(e) => handleChange('description', e.target.value)}
          placeholder="Mô tả chi tiết vấn đề của bạn..."
          rows={6}
          disabled={submitting}
        />
        {errors.description && (
          <span className={styles.errorText}>{errors.description}</span>
        )}
      </div>

      {/* Submit Button */}
      <div className={styles.actions}>
        <button
          type="submit"
          className={styles.submitButton}
          disabled={submitting}
        >
          {submitting ? 'Đang gửi...' : 'Gửi yêu cầu'}
        </button>
      </div>
    </form>
  );
};
