import { configureStore } from '@reduxjs/toolkit';
import authReducer from './slices/authSlice';
import uiReducer from './slices/uiSlice';
import notificationsReducer from './slices/notificationSlice';
import messagesInboxReducer from './slices/messagesInboxSlice';
import usersReducer from './slices/usersSlice';

// Web.Home owns: auth, UI, notifications, messages, settings.
// Tasks → @linm/task  |  Admin → @linm/admin  |  Medical → @linm/medical-incidents
export const store = configureStore({
  reducer: {
    auth: authReducer,
    ui: uiReducer,
    notifications: notificationsReducer,
    messagesInbox: messagesInboxReducer,
    users: usersReducer,
  },
  devTools: process.env.NODE_ENV !== 'production',
});

export type RootState = ReturnType<typeof store.getState>;
export type AppDispatch = typeof store.dispatch;
