/**
 * useAppToast — primary toast helper for Redux-connected components.
 *
 * Wraps `dispatch(addToast(...))` from uiSlice so callers don't need to
 * import addToast separately. API mirrors the old context `useToast()` hook
 * so migration is a one-line import swap.
 *
 * Usage:
 *   const toast = useAppToast();
 *   toast.success('Tạo công việc thành công');
 *   toast.error(error instanceof Error ? error.message : 'Đã có lỗi xảy ra, vui lòng thử lại');
 */

import { useCallback, useMemo } from 'react';
import { useAppDispatch } from '../store/hooks';
import { addToast } from '../store/slices/uiSlice';

export type AppToastType = 'success' | 'error' | 'warning' | 'info';

export function useAppToast() {
  const dispatch = useAppDispatch();

  // Stable reference — dispatch from Redux is already stable, so `show` never changes.
  const show = useCallback(
    (message: string, type: AppToastType) => dispatch(addToast({ message, type })),
    [dispatch],
  );

  // Memoize the returned object so components using toast in useCallback deps
  // don't get a new reference on every render (prevents infinite-fetch loops).
  return useMemo(() => ({
    success: (message: string) => show(message, 'success'),
    error:   (message: string) => show(message, 'error'),
    warning: (message: string) => show(message, 'warning'),
    info:    (message: string) => show(message, 'info'),

    /** Convenience: extract message from unknown catch value per TOAST_MESSAGE_RULES §4. */
    fromError: (error: unknown, fallback = 'Đã có lỗi xảy ra, vui lòng thử lại') =>
      show(error instanceof Error ? error.message : fallback, 'error'),
  }), [show]);
}
