import React, { useState, useEffect } from 'react';
import { useAlert } from '../../common/Alert';
import { SupportTicketCreate } from '../../../models/Help';
import { helpService } from '../../../services/helpService';
import { ContactForm } from '../ContactForm';
import { useAppToast } from '../../../hooks/useAppToast';
import styles from './ContactSupportPanel.module.css';

interface ContactSupportPanelProps {
  isOpen: boolean;
  onClose: () => void;
}

export const ContactSupportPanel: React.FC<ContactSupportPanelProps> = ({
  isOpen,
  onClose,
}) => {
  const alert = useAlert();
  const toast = useAppToast();
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    // Reset submitted state when panel opens
    if (isOpen) {
      setSubmitted(false);
    }
  }, [isOpen]);

  useEffect(() => {
    // Prevent body scroll when panel is open
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }

    return () => {
      document.body.style.overflow = '';
    };
  }, [isOpen]);

  const handleSubmit = async (ticket: SupportTicketCreate) => {
    try {
      setSubmitting(true);
      const result = await helpService.submitSupportTicket(ticket);
      console.log('Support ticket created:', result);
      setSubmitted(true);
      
      // Auto-close after 3 seconds
      setTimeout(() => {
        onClose();
      }, 3000);
    } catch (error: unknown) {
      toast.fromError(error, 'Không thể gửi yêu cầu hỗ trợ. Vui lòng thử lại.');
      alert.error('Không thể gửi yêu cầu hỗ trợ. Vui lòng thử lại.');
    } finally {
      setSubmitting(false);
    }
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Backdrop */}
      <div className={styles.backdrop} onClick={onClose} />

      {/* Panel */}
      <div className={`${styles.panel} ${isOpen ? styles.open : ''}`}>
        {/* Header */}
        <div className={styles.header}>
          <h2 className={styles.title}>Liên hệ Hỗ trợ</h2>
          <button className={styles.closeButton} onClick={onClose}>
            <i className="fas fa-times" />
          </button>
        </div>

        {/* Content */}
        <div className={styles.content}>
          {submitted ? (
            <div className={styles.success}>
              <div className={styles.successIcon}>
                <i className="fas fa-check" />
              </div>
              <h3 className={styles.successTitle}>Yêu cầu đã được gửi!</h3>
              <p className={styles.successMessage}>
                Đội ngũ hỗ trợ sẽ phản hồi bạn sớm nhất có thể.
                <br />
                Bạn sẽ nhận được thông báo qua email khi có cập nhật.
              </p>
            </div>
          ) : (
            <>
              {/* Contact Info */}
              <div className={styles.contactInfo}>
                <div className={styles.infoItem}>
                  <i className="fas fa-envelope" />
                  <div>
                    <strong>Email</strong>
                    <p>support@example.com</p>
                  </div>
                </div>
                <div className={styles.infoItem}>
                  <i className="fas fa-phone" />
                  <div>
                    <strong>Hotline</strong>
                    <p>1900 xxxx</p>
                  </div>
                </div>
                <div className={styles.infoItem}>
                  <i className="fas fa-clock" />
                  <div>
                    <strong>Giờ làm việc</strong>
                    <p>T2-T6: 8:00 - 17:30</p>
                  </div>
                </div>
              </div>

              {/* Form */}
              <ContactForm onSubmit={handleSubmit} submitting={submitting} />
            </>
          )}
        </div>
      </div>
    </>
  );
};
